import { Type } from "@google/genai";
import { analyzeImage } from './geminiClient';
import { OCRResult } from '../types';
import { ACTIVITIES } from '../constants';

export const ocrService = {
    /**
     * MATERYAL KLONLAMA VE DİJİTAL İKİZ ÜRETİMİ
     * Gelişmiş Mod: Sayfanın hem mantığını hem de görsel iskeletini (Visual Tree) çıkarır.
     */
    processImage: async (base64Image: string, targetType: 'CONVERTER' | 'ALGORITHM'): Promise<OCRResult> => {
        const prompt = `
        [ROL: KIDEMLİ EĞİTİM MATERYALİ MİMARI & BİLGİSAYARLI GÖRÜ UZMANI]
        GÖREV: Görüntüdeki çalışma sayfasının hem PEDAGOJİK hem de GÖRSEL DNA'SINI analiz et.

        ANALİZ KRİTERLERİ:
        1. **Görsel İskelet (Visual Tree):** Sayfadaki her bir bilgi bloğunun (başlık, soru, görsel, tablo) koordinatlarını ve kapladığı alanı (%) belirle.
        2. **Mantıksal Akış:** Öğrenciden istenen eylemin (eşleştirme, yazma, boyama) bilişsel haritasını çıkar.
        3. **Veri Karakteristiği:** Sorulardaki sayısal veya sözel verilerin zorluk ve stilini analiz et.

        ÇIKTI FORMATI (SADECE JSON):
        {
            "detectedType": "En yakın ActivityType",
            "title": "Orijinal Başlık",
            "description": "Pedagojik Amaç",
            "blueprint": "AI ÜRETİM KOMUTU: [Düzene ve mantığa sadık kalarak tamamen yeni verilerle içerik üretme talimatı]",
            "layoutJSON": {
                "structure": "grid | columns | random",
                "blocks": [
                    { "id": "b1", "type": "header", "relativeY": 0, "height": 10 },
                    { "id": "b2", "type": "question-group", "relativeY": 15, "height": 60, "cols": 2 }
                ]
            },
            "styleDNA": {
                "fontWeight": "bold | normal",
                "density": "high | medium | low",
                "borderStyle": "dashed | solid"
            },
            "baseType": "ACTIVITY_ID"
        }
        `;

        const schema = {
            type: Type.OBJECT,
            properties: {
                detectedType: { type: Type.STRING },
                title: { type: Type.STRING },
                description: { type: Type.STRING },
                blueprint: { type: Type.STRING },
                layoutJSON: {
                    type: Type.OBJECT,
                    properties: {
                        structure: { type: Type.STRING },
                        blocks: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    id: { type: Type.STRING },
                                    type: { type: Type.STRING },
                                    relativeY: { type: Type.NUMBER },
                                    height: { type: Type.NUMBER },
                                    cols: { type: Type.NUMBER, nullable: true }
                                }
                            }
                        }
                    }
                },
                styleDNA: {
                    type: Type.OBJECT,
                    properties: {
                        fontWeight: { type: Type.STRING },
                        density: { type: Type.STRING },
                        borderStyle: { type: Type.STRING }
                    }
                },
                baseType: { type: Type.STRING }
            },
            required: ['detectedType', 'title', 'blueprint', 'layoutJSON']
        };

        try {
            const result = await analyzeImage(base64Image, prompt, schema, 'gemini-3-flash-preview');

            return {
                rawText: '', 
                detectedType: result.baseType || 'AI_WORKSHEET_CONVERTER',
                title: result.title,
                description: result.description,
                generatedTemplate: result.blueprint,
                structuredData: {
                    layoutHint: result.layoutJSON,
                    styleDNA: result.styleDNA,
                    originalBlueprint: result.blueprint
                },
                baseType: result.baseType || 'AI_WORKSHEET_CONVERTER'
            };
        } catch (error) {
            console.error("Deep OCR Error:", error);
            throw new Error("Görsel mimarisi çözümlenemedi.");
        }
    }
};

import { WorksheetData, ActivityType, StyleSettings, WorksheetBlock } from '../types';

/**
 * Sayfa Kapasite Mantığı v2.0:
 * Artık sadece item sayısına değil, blokların fiziksel 'weight' (yükseklik) değerlerine bakar.
 */

const MAX_PAGE_WEIGHT = 100; // Standart A4 kapasitesi

const getBlockWeight = (block: WorksheetBlock): number => {
    if (block.weight) return block.weight;

    switch(block.type) {
        case 'header': return 15;
        case 'image': return 30;
        case 'question': return 12;
        case 'grid': return 40;
        case 'text': return Math.min(40, (block.content?.length || 0) / 20);
        default: return 10;
    }
};

export const paginationService = {
    process: (data: WorksheetData, activityType: ActivityType, settings?: StyleSettings): WorksheetData => {
        if (!data || !Array.isArray(data) || data.length === 0) return [];
        if (settings && settings.smartPagination === false) return data;

        const newPages: any[] = [];

        data.forEach((originalPageData) => {
            // Eğer veride 'blocks' varsa yeni sistem, yoksa eski listelere (puzzles, operations vb.) bak
            const listKey = originalPageData.blocks ? 'blocks' : (originalPageData.puzzles ? 'puzzles' : (originalPageData.operations ? 'operations' : (originalPageData.steps ? 'steps' : (originalPageData.problems ? 'problems' : (originalPageData.items ? 'items' : null)))));

            if (listKey && Array.isArray(originalPageData[listKey])) {
                let currentItems: any[] = [];
                let currentWeight = 0;

                originalPageData[listKey].forEach((item: any) => {
                    // Blok ağırlığı hesapla
                    const weight = originalPageData.blocks ? getBlockWeight(item) : 10; // Fallback for old items

                    if (currentWeight + weight > MAX_PAGE_WEIGHT && currentItems.length > 0) {
                        newPages.push({ 
                            ...originalPageData, 
                            [listKey]: currentItems, 
                            isContinuation: newPages.length > 0,
                            pageTotalWeight: currentWeight
                        });
                        currentItems = [];
                        currentWeight = 0;
                    }
                    currentItems.push(item);
                    currentWeight += weight;
                });

                if (currentItems.length > 0) {
                    newPages.push({ 
                        ...originalPageData, 
                        [listKey]: currentItems, 
                        isContinuation: newPages.length > 0,
                        pageTotalWeight: currentWeight
                    });
                }
            } else {
                newPages.push(originalPageData);
            }
        });

        return newPages;
    }
};

