export const generateMapInstructionFromAI = async (options: GeneratorOptions): Promise<MapInstructionData[]> => {
    const { customInput, difficulty, itemCount, studentContext } = options;

    let visualContext = "";
    let detectedPoints: any[] = [];

    // Eğer kullanıcı özel bir harita yüklediyse, önce onu analiz et
    if (customInput) {
        try {
            const analysis = await ocrService.analyzeMapImage(customInput);
            visualContext = `HARİTA ANALİZİ: Bu harita bir "${analysis.mapContext}" haritasıdır. Üzerindeki önemli noktalar: ${analysis.points.map((p:any) => p.name).join(', ')}.`;
            detectedPoints = analysis.points;
        } catch (e) {
            console.error("Map analysis failed, falling back to generic", e);
        }
    }

    const prompt = `
    ${PEDAGOGICAL_BASE}
    ${MAP_DETECTIVE_PROMPT}

    PARAMETRELER:
    - Zorluk: ${difficulty}
    - Soru Sayısı: ${itemCount || 8}
    - Görsel Bağlam: ${visualContext || "Standart Türkiye Siyasi Haritası"}

    GÖREV: Harita dedektifi yönergeleri oluştur. 
    Eğer harita özel ise yönergeler harita üzerindeki nesneleri hedef almalı.
    Eğer standart ise şehirler ve bölgeler üzerinden ilerle.

    ÇIKTI FORMATI:
    {
        "title": "Harita Dedektifi: [Harita Adı]",
        "instruction": "...",
        "pedagogicalNote": "...",
        "instructions": ["Yönerge 1", "Yönerge 2", ...],
        "cities": [ { "id": "tr-34", "name": "İstanbul", "x": 175, "y": 115 } ]
    }
    `;

    const schema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
            cities: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        id: { type: Type.STRING },
                        name: { type: Type.STRING },
                        x: { type: Type.NUMBER },
                        y: { type: Type.NUMBER }
                    }
                }
            }
        }
    };

    const result = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');

    // Yüklenen görseli veriye enjekte et
    return [{
        ...result,
        imageBase64: customInput,
        cities: customInput ? detectedPoints : result.cities // AI tarafından haritadan çıkarılan noktalar
    }] as MapInstructionData[];
};

export const generateVisualOddOneOutFromAI = async (options: GeneratorOptions): Promise<VisualOddOneOutData[]> => {
    const { difficulty, worksheetCount, visualType, distractionLevel, gridSize, studentContext } = options;

    const typeDesc = visualType === 'geometric' ? 'Karmaşık Geometrik Şekiller (Düz çizgiler)' : 
                   visualType === 'abstract' ? 'Soyut Desenler ve Eğri Çizgiler (Bezier paths)' : 
                   visualType === 'character' ? 'Ayna Harf ve Rakamlar (b/d, p/q, 6/9 vb.)' : 'Karmaşık poligonlar ve fraktal benzeri yapılar';

    const prompt = `
    [GÖREV: GÖRSEL AYRİT ETME (VISUAL ODD-ONE-OUT) TANISAL ETKİNLİK]
    [MODEL: Gemini 3.0 Flash Preview Multimodal]

    PARAMETRELER:
    - Mimari Tip: ${typeDesc}.
    - Zorluk: ${difficulty}.
    - Çeldirici Hassasiyeti: ${distractionLevel}.
    - Satır Başı Öğe Sayısı: ${gridSize || 4}.
    - Öğrenci Profili: ${studentContext?.diagnosis?.join(', ') || 'Genel Gelişim'}.

    İÇERİK MİMARİSİ:
    1. Eğer 'character' seçildiyse: 'label' alanına tek karakter (örn: "b") yaz.
    2. Diğer tipler için 'svgPaths' dizisinde 100x100 koordinat sistemine uygun geçerli SVG 'd' yolları döndür.
    3. Her satırda bir adet "Odd One" (Farklı) ve diğerleri birbirinin aynısı "Base" öğeler üret.
    4. Farkı oluştururken ${distractionLevel} seviyesini baz al (renk, rotasyon, bir çizgi eksikliği veya ayna görüntüsü).

    ÇIKTI FORMATI:
    - rows: [{ items: [{ svgPaths?: [{ d: string, fill?: string, stroke?: string, strokeWidth?: number }], label?: string, rotation?: number, scale?: number }], correctIndex: number, reason: string }]

    ${PEDAGOGICAL_PROMPT}
    `;

    const singleSchema = {
        type: Type.OBJECT,
        properties: {
            title: { type: Type.STRING },
            instruction: { type: Type.STRING },
            pedagogicalNote: { type: Type.STRING },
            difficultyLevel: { type: Type.STRING },
            distractionLevel: { type: Type.STRING },
            rows: { 
                type: Type.ARRAY, 
                items: { 
                    type: Type.OBJECT, 
                    properties: { 
                        items: { 
                            type: Type.ARRAY, 
                            items: { 
                                type: Type.OBJECT, 
                                properties: { 
                                    svgPaths: { 
                                        type: Type.ARRAY, 
                                        items: { 
                                            type: Type.OBJECT, 
                                            properties: { 
                                                d: { type: Type.STRING }, 
                                                fill: { type: Type.STRING }, 
                                                stroke: { type: Type.STRING },
                                                strokeWidth: { type: Type.NUMBER }
                                            } 
                                        } 
                                    },
                                    label: { type: Type.STRING },
                                    rotation: { type: Type.NUMBER },
                                    scale: { type: Type.NUMBER },
                                    isMirrored: { type: Type.BOOLEAN }
                                } 
                            } 
                        }, 
                        correctIndex: { type: Type.INTEGER }, 
                        reason: { type: Type.STRING }
                    }, 
                    required: ["items", "correctIndex"] 
                } 
            }
        },
        required: ["title", "instruction", "rows", "pedagogicalNote"]
    };

    const schema = { type: Type.ARRAY, items: singleSchema };
    return generateWithSchema(prompt, schema, 'gemini-3-flash-preview') as Promise<VisualOddOneOutData[]>;
};

export const generateFindTheDifferenceFromAI = async (options: GeneratorOptions): Promise<FindTheDifferenceData[]> => {
