/**
 * Gizemli Sayılar: Dedektiflik Dosyası (AI Modu)
 * Derinlemesine mantık katmanları ve toplam kontrolü entegre edildi.
 */
export const generateNumberLogicRiddlesFromAI = async (options: GeneratorOptions): Promise<NumberLogicRiddleData[]> => {
    const { difficulty, numberRange = '1-50', itemCount = 6, studentContext, gridSize = 3 } = options;

    const rule = `
    [GÖREV]: Sayısal Mantık Bilmeceleri.
    [ADET]: ${itemCount} bağımsız bilmece.
    [MENZİL]: ${numberRange}
    [İPUCU DERİNLİĞİ]: ${gridSize} adet farklı mantık katmanı.

    ÜRETİM STRATEJİSİ:
    1. Her bilmece için bir "Hedef Sayı" belirle.
    2. Bu sayıyı ele veren ${gridSize} adet farklı tipte ipucu üret:
       - 'parity': Tek mi çift mi?
       - 'range': Hangi onlukta veya hangi sayıya ne kadar yakın?
       - 'digits': Rakamları toplamı, basamak sayısı vb.
       - 'operation': "X'in 2 katı", "Y'den 5 eksik" gibi aritmetik kancalar.
    3. 'sumTarget': Üretilen tüm doğru cevapların matematiksel toplamıdır. (Mutlaka hatasız hesapla).
    4. 'boxes': Her bilmece için 5 adet 2'li sayı grubu oluştur. (Zemin kalabalığı için).
    5. 'options': 3 adet çeldirici ve 1 doğru cevap. Çeldiriciler hedefe yakın olmalı.
    `;

    const prompt = getMathPrompt("Gizemli Sayılar (Yüksek Yoğunluklu)", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                sumTarget: { type: Type.INTEGER },
                sumMessage: { type: Type.STRING },
                numberRangeStart: { type: Type.INTEGER },
                numberRangeEnd: { type: Type.INTEGER },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            riddle: { type: Type.STRING },
                            riddleParts: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: { 
                                        text: { type: Type.STRING }, 
                                        icon: { type: Type.STRING },
                                        type: { type: Type.STRING } 
                                    },
                                    required: ['text', 'icon', 'type']
                                }
                            },
                            visualHint: { type: Type.STRING, description: "SVG veya emoji ipucu tasviri" },
                            boxes: { 
                                type: Type.ARRAY, 
                                items: { 
                                    type: Type.ARRAY, 
                                    items: { type: Type.INTEGER } 
                                } 
                            },
                            options: { type: Type.ARRAY, items: { type: Type.STRING } },
                            answer: { type: Type.STRING },
                            answerValue: { type: Type.INTEGER }
                        },
                        required: ['riddle', 'riddleParts', 'boxes', 'options', 'answer', 'answerValue']
                    }
                }
            }
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

/**
 * Sembolik İşlem Zinciri (AI Modu)
 */
export const generateNumberPathLogicFromAI = async (options: GeneratorOptions): Promise<NumberPathLogicData[]> => {
    const { difficulty, codeLength = 3, itemCount = 6, studentContext } = options;

    const rule = `
    [GÖREV]: Sembolik İşlem Zinciri Üret.
    [ZORLUK]: ${difficulty}
    [ZİNCİR UZUNLUĞU]: ${codeLength} adım.
    [ADET]: ${itemCount} adet bağımsız işlem zinciri.

    KURALLAR:
    1. Bir 'legend' (lejant) oluştur: Her sembol (circle, square, triangle, hexagon) bir işleme (+5, -2, x3) denk gelmeli.
    2. 'chains' dizisinde bir başlangıç sayısı (startNumber) ve bu sayıya uygulanacak sembol dizisini ver.
    3. Her adımda sonucun tam sayı ve pozitif kalmasını sağla.
    4. En az 4 farklı sembol-renk çifti kullan.
    `;

    const prompt = getMathPrompt("Sembolik İşlem Zinciri", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                legend: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            symbol: { type: Type.STRING, enum: ['circle', 'square', 'triangle', 'hexagon', 'star'] },
                            operation: { type: Type.STRING, enum: ['+', '-', 'x'] },
                            value: { type: Type.INTEGER },
                            color: { type: Type.STRING }
                        },
                        required: ['symbol', 'operation', 'value', 'color']
                    }
                },
                chains: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            startNumber: { type: Type.INTEGER },
                            steps: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        symbol: { type: Type.STRING },
                                        expectedValue: { type: Type.INTEGER, nullable: true }
                                    },
                                    required: ['symbol']
                                }
                            }
                        },
                        required: ['startNumber', 'steps']
                    }
                }
            },
            required: ['title', 'legend', 'chains']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

