import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, NumberLogicRiddleData } from '../../types';
import { getMathPrompt } from './prompts';

export const generateNumberLogicRiddlesFromAI = async (options: GeneratorOptions): Promise<NumberLogicRiddleData[]> => {
    const { difficulty, itemCount = 6, gridSize = 3, showSumTarget, studentContext } = options;

    const rule = `
    [GÖREV: SAYISAL MANTIK BİLMECELERİ - DEDEKTİFLİK DOSYASI]
    ADET: ${itemCount} adet bağımsız bilmece.
    İPUCU DERİNLİĞİ: Her bilmece için ${gridSize} adet farklı mantık katmanı.
    ZORLUK: ${difficulty}

    ÜRETİM KURALLARI:
    1. Her bilmece için bir 'Hedef Sayı' belirle.
    2. 'riddleParts' içinde şu tiplerden ${gridSize} adet ipucu oluştur: 
       - 'parity' (tek/çift)
       - 'digits' (rakam toplamı, basamak farkı)
       - 'comparison' (yakınlık, aralık)
       - 'arithmetic' (katlar, bölenler, temel işlemler).
    3. Her ipucu için anlamlı bir FontAwesome ikonu (fa-...) ata.
    4. 'visualDistraction': Sayfanın altına serpiştirilecek 5 adet şüpheli sayı üret (çeldirici).
    5. 'sumTarget': Tüm doğru cevapların matematiksel toplamını hatasız hesapla.
    6. 'options': 4 şıklı seçenek seti üret (1 doğru, 3 mantıklı çeldirici).

    DİKKAT: Disleksi dostu dil kullan, yönergeler kısa ve net olsun.
    `;

    const prompt = getMathPrompt("Gizemli Sayılar: Kompakt Analiz", difficulty, rule, studentContext);

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                sumTarget: { type: Type.INTEGER },
                sumMessage: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            riddleParts: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        text: { type: Type.STRING },
                                        icon: { type: Type.STRING },
                                        type: { type: Type.STRING }
                                    },
                                    required: ['text', 'icon', 'type']
                                }
                            },
                            visualDistraction: { type: Type.ARRAY, items: { type: Type.INTEGER } },
                            options: { type: Type.ARRAY, items: { type: Type.STRING } },
                            answer: { type: Type.STRING },
                            answerValue: { type: Type.INTEGER }
                        },
                        required: ['riddleParts', 'options', 'answer', 'answerValue']
                    }
                }
            }
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};
