import React from 'react';
import { NumberLogicRiddleData } from '../../../types';
import { PedagogicalHeader } from '../common';
import { EditableElement, EditableText } from '../../Editable';

export const NumberLogicRiddleSheet: React.FC<{ data: NumberLogicRiddleData }> = ({ data }) => {
    const itemCount = data.puzzles?.length || 0;

    // Dinamik grid sütun hesaplama (Daha kompakt görünüm için)
    const gridCols = itemCount <= 4 ? 'grid-cols-2' : 'grid-cols-3';

    return (
        <div className="flex flex-col h-full bg-white text-black font-lexend p-1 overflow-hidden">
            <PedagogicalHeader 
                title={data.title || "Sayısal Mantık Bilmeceleri"} 
                instruction={data.instruction || "Bilmeceleri çöz, doğru olanı işaretle."} 
                note={data.pedagogicalNote} 
            />

            <div className={`grid ${gridCols} gap-3 mt-2 flex-1 content-start`}>
                {(data.puzzles || []).map((puzzle, pIdx) => (
                    <EditableElement key={pIdx} className="flex flex-col border-[1.5px] border-zinc-900 rounded-2xl p-4 bg-white shadow-sm break-inside-avoid relative group hover:border-indigo-600 transition-all">
                        {/* Soru Numarası */}
                        <div className="absolute -top-2 -left-1 w-7 h-7 bg-zinc-900 text-white rounded-lg flex items-center justify-center font-black text-xs shadow-md border border-white">
                            {pIdx + 1}
                        </div>

                        {/* Bilmece Parçacıkları (Chunking) */}
                        <div className="space-y-2 mb-4">
                            {puzzle.riddleParts.map((part, hIdx) => (
                                <div key={hIdx} className="flex items-start gap-2">
                                    <div className="w-5 h-5 rounded bg-zinc-100 flex items-center justify-center text-zinc-500 shrink-0 mt-0.5">
                                        <i className={`fa-solid ${part.icon} text-[10px]`}></i>
                                    </div>
                                    <p className="text-[11px] font-bold leading-tight text-zinc-800">
                                        <EditableText value={part.text} tag="span" />
                                    </p>
                                </div>
                            ))}
                        </div>

                        {/* Çeldirici Sayı Bulutu (Kompakt) */}
                        <div className="flex flex-wrap gap-1 justify-center mb-3 opacity-20 group-hover:opacity-40 transition-opacity select-none border-t border-zinc-50 pt-2">
                            {(puzzle.visualDistraction || []).map((num, nIdx) => (
                                <span key={nIdx} className="text-[8px] font-mono font-black italic">{num}</span>
                            ))}
                        </div>

                        {/* Şıklar - Print Optimized Grid */}
                        <div className="mt-auto grid grid-cols-2 gap-1.5">
                            {puzzle.options.map((opt, oIdx) => (
                                <div key={oIdx} className="flex items-center gap-2 p-1.5 border border-zinc-200 rounded-lg hover:border-zinc-900 transition-colors cursor-pointer">
                                    <div className="w-4 h-4 rounded border-2 border-zinc-300 bg-white flex items-center justify-center text-[8px] font-black">{String.fromCharCode(65 + oIdx)}</div>
                                    <span className="text-[11px] font-black text-zinc-900">{opt}</span>
                                </div>
                            ))}
                        </div>
                    </EditableElement>
                ))}
            </div>

            {/* Sum-Check Kontrol Paneli (Yönetici İşlev Desteği) */}
            {data.sumTarget > 0 && (
                <div className="mt-4 border-2 border-zinc-900 rounded-3xl p-4 bg-zinc-50 flex items-center justify-between break-inside-avoid shadow-inner">
                    <div className="flex items-center gap-4">
                         <div className="w-10 h-10 bg-zinc-900 text-white rounded-xl flex items-center justify-center text-lg"><i className="fa-solid fa-calculator"></i></div>
                         <div>
                            <h4 className="text-sm font-black tracking-tight uppercase leading-none">Toplam Kontrolü</h4>
                            <p className="text-[9px] text-zinc-500 font-bold mt-1">Bulduğun tüm sonuçları topla.</p>
                         </div>
                    </div>

                    <div className="flex items-center gap-6">
                        <div className="text-center">
                            <span className="text-[8px] font-black text-zinc-400 uppercase tracking-widest block">Hedef</span>
                            <div className="text-2xl font-black text-indigo-600 font-mono leading-none">{data.sumTarget}</div>
                        </div>
                        <div className="w-px h-8 bg-zinc-200"></div>
                        <div className="text-center">
                            <span className="text-[8px] font-black text-zinc-400 uppercase tracking-widest block">Senin Sonucun</span>
                            <div className="w-16 h-8 border-b-2 border-dashed border-zinc-300 flex items-center justify-center font-black text-xl text-transparent">?</div>
                        </div>
                    </div>
                </div>
            )}

            <div className="mt-4 flex justify-between items-center text-[7px] font-black text-zinc-300 uppercase tracking-[0.4em] px-4">
                <span>Bursa Disleksi AI • Sayısal Mantık v2.1</span>
                <div className="flex gap-4">
                     <i className="fa-solid fa-brain-circuit"></i>
                     <i className="fa-solid fa-print"></i>
                </div>
            </div>
        </div>
    );
};

