export const generateShapeCountingFromAI = async (options: GeneratorOptions): Promise<ShapeCountingData[]> => {
    const { difficulty, itemCount = 4, studentContext, gridSize = 3 } = options;

    const prompt = `
    ${PEDAGOGICAL_BASE}

    GÖREV: [ÜST DÜZEY GÖRSEL MUHAKEME] - "Kaç Tane Üçgen Var?" etkinliği üret.
    ZORLUK SEVİYESİ: ${difficulty}
    ADET: ${itemCount} adet karmaşık şekil.
    İPUCU SAYISI: ${gridSize} adet (Her şekil için).

    MİMARİ TİPLER (Karışık Kullan):
    1. 'nested': Büyük bir üçgenin içinde çizgilerle oluşan hiyerarşik katmanlar.
    2. 'complex_polygon': Bir Kare, Beşgen veya Altıgenin iç köşegenlerinden doğan gizli üçgenler.
    3. 'mosaic': Yan yana duran şekillerin birleşerek oluşturduğu büyük optik üçgenler.
    4. 'chaotic': Bir daire veya çerçeve içinde birbirini kesen 5-8 arası doğrunun oluşturduğu karmaşa.

    TEKNİK KRİTERLER:
    - svgPaths: 100x100 koordinat sisteminde geçerli SVG 'd' yolları.
    - correctCount: Kesinlikle doğru hesaplanmalı (Hata kabul edilemez).
    - clues: Öğrenciye "Önce küçükleri say", "Şu köşeye odaklan" gibi ${gridSize} adet stratejik ipucu ver.
    - pedagogicalNote: Bu tip karmaşık saymanın 'yönetici işlevler' ve 'çalışma belleği' üzerindeki etkisini açıkla.

    ${IMAGE_GENERATION_GUIDE}
    ÇIKTI: Sadece JSON döndür.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                settings: {
                    type: Type.OBJECT,
                    properties: {
                        difficulty: { type: Type.STRING },
                        itemCount: { type: Type.NUMBER },
                        showClues: { type: Type.BOOLEAN }
                    }
                },
                figures: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            type: { type: Type.STRING },
                            targetShape: { type: Type.STRING },
                            correctCount: { type: Type.INTEGER },
                            clues: { type: Type.ARRAY, items: { type: Type.STRING } },
                            svgPaths: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        d: { type: Type.STRING },
                                        fill: { type: Type.STRING },
                                        stroke: { type: Type.STRING },
                                        strokeWidth: { type: Type.NUMBER }
                                    }
                                }
                            }
                        },
                        required: ['svgPaths', 'correctCount', 'clues']
                    }
                }
            },
            required: ['title', 'instruction', 'figures']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

