export const generateShapeCountingFromAI = async (options: GeneratorOptions): Promise<ShapeCountingData[]> => {
    const { difficulty, itemCount = 4, distractionLevel = 'medium', variant = 'standard', gridSize = 3 } = options;

    // Yoğunluk seviyesine göre çizgi sayısı belirleme
    const complexityMap = {
        'low': '3-5 kesişen doğru (basit yapılar)',
        'medium': '6-9 kesişen doğru (orta seviye)',
        'high': '10-14 kesişen doğru (karmaşık yapılar)',
        'extreme': '15+ kesişen doğru (fraktal benzeri, çok zor)'
    };

    const varietyDesc = variant === 'mixed' 
        ? "Üçgen, Kare, Yıldız, Altıgen ve Pentagram tabanlı karmaşık poligonlar kullan."
        : "Sadece büyük bir ana üçgenin iç bölmelendirmelerini kullan (Hiyerarşik üçgenler).";

    const prompt = `
    ${PEDAGOGICAL_BASE}

    GÖREV: [GÖRSEL-UZAMSAL ANALİZ ETKİNLİĞİ] - "Kaç Tane Üçgen Var?"
    ZORLUK SEVİYESİ: ${difficulty}
    ADET: ${itemCount} adet bağımsız geometrik figür üret.
    YOĞUNLUK: ${complexityMap[distractionLevel as keyof typeof complexityMap]}.
    ÇEŞİTLİLİK: ${varietyDesc}
    İPUCU DERİNLİĞİ: ${gridSize} adet stratejik adım (Örn: "Önce en büyükleri say", "Kesişim noktalarına odaklan").

    TEKNİK ŞARTNAME:
    1. svgPaths: 100x100 koordinat sisteminde GEÇERLİ ve temiz SVG 'd' yolları.
    2. correctCount: Şekil içindeki tüm olası (küçük, orta, büyük ve birleşik) üçgenlerin KESİN sayısı. 
    3. Stratejik İpuçları (clues): Öğrencinin sistematik sayma becerisini geliştirecek ${gridSize} adet kısa yönerge.
    4. Tasarım: Modern, minimalist, yüksek kontrastlı siyah-beyaz çizgiler (Baskı dostu).

    ${IMAGE_GENERATION_GUIDE}
    ÇIKTI: Sadece JSON döndür.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                settings: {
                    type: Type.OBJECT,
                    properties: {
                        difficulty: { type: Type.STRING },
                        itemCount: { type: Type.NUMBER },
                        density: { type: Type.STRING },
                        variety: { type: Type.STRING }
                    }
                },
                figures: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            type: { type: Type.STRING },
                            correctCount: { type: Type.INTEGER },
                            clues: { type: Type.ARRAY, items: { type: Type.STRING } },
                            svgPaths: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        d: { type: Type.STRING },
                                        strokeWidth: { type: Type.NUMBER }
                                    }
                                }
                            }
                        },
                        required: ['svgPaths', 'correctCount', 'clues']
                    }
                }
            },
            required: ['title', 'instruction', 'figures']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

