                            ANS: {fig.correctCount}
                        </div>
                    </EditableElement>
                ))}
            </div>

            {/* Profesyonel Footer Şeridi */}
            <div className="mt-4 pt-4 border-t border-zinc-100 flex justify-between items-end opacity-40 px-6">
                 <div className="flex gap-12">
