import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, LetterConnectingData } from '../../types';

export const generateLetterConnectingFromAI = async (options: GeneratorOptions): Promise<LetterConnectingData[]> => {
    const { topic, difficulty, itemCount = 6, variant = 'curved' } = options;

    const prompt = `
    [GÖREV: HARF BAĞLAMA ETKİNLİĞİ (LETTER CONNECTING)]
    ZORLUK: ${difficulty}
    KONU: ${topic || 'Karma'}
    ADET: ${itemCount} bağımsız görev.

    KURALLAR:
    1. Her görev bir kelimeyi hedefler. Kelimeler ${difficulty === 'Başlangıç' ? '3-4' : '5-8'} harfli olmalı.
    2. 'letters' dizisi: Kelimenin her harfi için 0-100 arası x,y koordinatı ata.
    3. Koordinatlar harflerin birbirine çok yakın (üst üste) olmamasını sağlamalı.
    4. ${difficulty === 'Zor' || difficulty === 'Uzman' ? 'Her kelime için en az 3 adet çeldirici (isDistractor: true) harf ekle (Örn: b yerine d).' : 'Çeldirici ekleme.'}
    5. Koordinatlar kaotik ama takip edilebilir bir akışta olmalı.

    ÇIKTI: JSON Dizisi.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                items: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            word: { type: Type.STRING },
                            imagePrompt: { type: Type.STRING },
                            letters: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        char: { type: Type.STRING },
                                        x: { type: Type.NUMBER },
                                        y: { type: Type.NUMBER },
                                        order: { type: Type.NUMBER },
                                        isDistractor: { type: Type.BOOLEAN }
                                    },
                                    required: ['char', 'x', 'y', 'order', 'isDistractor']
                                }
                            }
                        },
                        required: ['word', 'letters']
                    }
                }
            },
            required: ['title', 'instruction', 'items']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

