export const LetterConnectingSheet: React.FC<{ data: LetterConnectingData }> = ({ data }) => {
    const items = data.items || [];
    const itemCount = items.length;

    // Grid yerleşimi: Öğe sayısına göre kolon ve yükseklik ayarı
    const gridCols = itemCount <= 4 ? 'grid-cols-2' : (itemCount <= 8 ? 'grid-cols-2 md:grid-cols-3' : 'grid-cols-3 md:grid-cols-4');
    const areaHeight = itemCount > 8 ? 'h-40' : 'h-64';

    return (
        <div className="flex flex-col h-full bg-white font-lexend text-black p-1 overflow-hidden select-none">
            <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} />

            <div className={`grid ${gridCols} gap-2 mt-2 flex-1 content-start`}>
                {items.map((item, idx) => (
                    <EditableElement key={idx} className="flex flex-col border-[2px] border-zinc-900 rounded-[2rem] bg-white group hover:border-indigo-600 transition-all p-3 relative overflow-hidden break-inside-avoid shadow-sm">

                        {/* Sayı Rozeti */}
                        <div className="absolute top-0 left-0 bg-zinc-900 text-white px-3 py-1 rounded-br-2xl font-black text-[10px] z-10">
                            {idx + 1}
                        </div>

                        {/* Kelime Görseli */}
                        <div className="w-full flex justify-center mb-1">
                            <div className="w-12 h-12 bg-zinc-50 rounded-xl overflow-hidden shadow-inner border border-zinc-100">
                                <ImageDisplay prompt={item.imagePrompt} className="w-full h-full object-contain" />
                            </div>
                        </div>

                        {/* Harf Alanı (Canvas simülasyonu) */}
                        <div className={`relative w-full ${areaHeight} bg-zinc-50/30 rounded-2xl border-2 border-dashed border-zinc-100 mb-2`}>
                            {item.letters.map((l, lIdx) => (
                                <div 
                                    key={lIdx}
                                    className="absolute transform -translate-x-1/2 -translate-y-1/2 flex flex-col items-center gap-0.5"
                                    style={{ left: `${l.x}%`, top: `${l.y}%` }}
                                >
                                    <div className={`w-8 h-8 rounded-full border-2 bg-white flex items-center justify-center font-black text-sm shadow-xs ${l.isDistractor ? 'border-zinc-200 text-zinc-300' : 'border-zinc-800 text-zinc-900'}`}>
                                        <EditableText value={l.char} tag="span" />
                                    </div>
                                    <div className="w-1.5 h-1.5 rounded-full bg-zinc-300"></div>
                                </div>
                            ))}
                        </div>

                        {/* Cevap Alanı */}
                        <div className="mt-auto pt-2 border-t border-zinc-100">
                            <div className="w-full h-8 border-b-2 border-dashed border-zinc-300 flex items-center justify-center">
                                <span className="text-[9px] font-black text-zinc-300 uppercase tracking-[0.2em] italic">KELİMEYİ YAZ</span>
                            </div>
                        </div>

                        {/* Gizli Cevap Anahtarı */}
                        <div className="absolute top-1 right-2 opacity-0 group-hover:opacity-10 transition-opacity rotate-180 text-[8px] font-black pointer-events-none">
                            ANS: {item.word}
                        </div>
                    </EditableElement>
                ))}
            </div>

            <div className="mt-4 pt-4 border-t border-zinc-100 flex justify-between items-center opacity-30 px-6">
                <p className="text-[7px] text-zinc-400 font-bold uppercase tracking-[0.5em]">Bursa Disleksi AI • Harf Bağlama Atölyesi v1.0</p>
                <div className="flex gap-4">
                     <i className="fa-solid fa-code-merge"></i>
                     <i className="fa-solid fa-font"></i>
