// --- HELPERS FOR DIRECTIONAL TRACKING ---
const DIRS = [
    { name: 'right', dx: 1, dy: 0 },
    { name: 'down', dx: 0, dy: 1 },
    { name: 'left', dx: -1, dy: 0 },
    { name: 'up', dx: 0, dy: -1 }
];

export const generateOfflineDirectionalTracking = async (options: GeneratorOptions): Promise<DirectionalTrackingData[]> => {
    const { worksheetCount, difficulty, itemCount = 4, topic } = options;
    const rows = options.gridRows || 6;
    const cols = options.gridCols || 6;
    const results: DirectionalTrackingData[] = [];

    for (let p = 0; p < worksheetCount; p++) {
        const puzzles = [];
        const wordPool = getWordsForDifficulty(difficulty, topic || 'Rastgele');

        for (let i = 0; i < itemCount; i++) {
            let targetWord = getRandomItems(wordPool, 1)[0].toUpperCase();
            // Kelime uzunluğu grid kapasitesinin yarısını geçmemeli
            if (targetWord.length > (rows * cols) / 2) targetWord = targetWord.substring(0, Math.floor((rows * cols) / 2));

            const grid = Array.from({length: rows}, () => Array(cols).fill(''));
            let currentR = getRandomInt(0, rows - 1);
            let currentC = getRandomInt(0, cols - 1);
            const startPos = { r: currentR, c: currentC };

            grid[currentR][currentC] = targetWord[0];
            const path: string[] = [];

            for (let charIdx = 1; charIdx < targetWord.length; charIdx++) {
                const possibleMoves = DIRS.filter(d => {
                    const nr = currentR + d.dy;
                    const nc = currentC + d.dx;
                    return nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc] === '';
                });

                if (possibleMoves.length === 0) break; // Kelimeyi burada kes

                const move = possibleMoves[getRandomInt(0, possibleMoves.length - 1)];
                path.push(move.name);
                currentR += move.dy;
                currentC += move.dx;
                grid[currentR][currentC] = targetWord[charIdx];
            }

            // Boşlukları klinik çeldiricilerle (Ayna harfler) doldur
            const distractors = ['B', 'D', 'P', 'Q', 'M', 'N', 'U', 'Ü'];
            for(let r=0; r<rows; r++) {
                for(let c=0; c<cols; c++) {
                    if (grid[r][c] === '') grid[r][c] = getRandomItems(distractors, 1)[0];
                }
            }

            puzzles.push({
                grid,
                path,
                startPos,
                targetWord: targetWord.substring(0, path.length + 1)
            });
        }

        results.push({
            title: "Yönsel İz Sürme & Kod Çözme",
            instruction: "Başlangıç hücresinden başlayarak okları takip et, geçtiğin harfleri birleştir ve gizli kelimeyi bul.",
            pedagogicalNote: "Uzamsal yönelim, göz takibi ve fonolojik sentez becerilerini destekleyen bir dikkati sürdürme çalışmasıdır.",
            puzzles
        });
    }
    return results;
};

