import { ActivityType, WorksheetData, SavedWorksheet, SingleWorksheetData, StyleSettings, View, CollectionItem, WorkbookSettings, StudentProfile, AssessmentReport } from '../types';
import Worksheet from './Worksheet';
import { Toolbar } from './Toolbar';
import { EditableContext } from './Editable';
import { paginationService } from '../services/paginationService';
import { SkeletonLoader } from './SkeletonLoader';

interface ContentAreaProps {
  currentView: View;
  onBackToGenerator: () => void;
  activityType: ActivityType | null;
  worksheetData: WorksheetData;
  isLoading: boolean;
  error: string | null;
  styleSettings: StyleSettings;
  onStyleChange: (settings: StyleSettings) => void;
  onSave: (name: string, activityType: ActivityType, data: SingleWorksheetData[]) => void;
  onLoadSaved: (worksheet: SavedWorksheet) => void;
  onFeedback: () => void;
  onOpenAuth: () => void;
  workbookItems: CollectionItem[];
  setWorkbookItems: React.Dispatch<React.SetStateAction<CollectionItem[]>>;
  workbookSettings: WorkbookSettings;
  setWorkbookSettings: React.Dispatch<React.SetStateAction<WorkbookSettings>>;
  onAddToWorkbook: () => void;
  studentProfile?: StudentProfile | null;
  zenMode: boolean;
  toggleZenMode: () => void;
}

export const ContentArea: React.FC<ContentAreaProps> = ({
  currentView, activityType, worksheetData, isLoading, error, styleSettings, onStyleChange, onSave, zenMode, toggleZenMode
}) => {
    const [scale, setScale] = useState(0.85);
    const [processedData, setProcessedData] = useState<SingleWorksheetData[]>([]);
    const scrollContainerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!worksheetData) { setProcessedData([]); return; }
        const safeData = Array.isArray(worksheetData) ? worksheetData : [worksheetData];
        const paged = paginationService.process(safeData, activityType!, styleSettings);
        setProcessedData(paged || safeData);
    }, [worksheetData, activityType, styleSettings]);

    useEffect(() => {
        const handleWheel = (e: WheelEvent) => {
            if (e.ctrlKey) {
                e.preventDefault();
                const delta = -e.deltaY * 0.001;
                setScale(s => Math.min(Math.max(0.3, s + delta), 2.5));
            }
        };
        scrollContainerRef.current?.addEventListener('wheel', handleWheel, { passive: false });
        return () => scrollContainerRef.current?.removeEventListener('wheel', handleWheel);
    }, []);

    return (
        <EditableContext.Provider value={{ isEditMode: false, zoom: scale }}>
            <main className="flex-1 flex flex-col h-full bg-[var(--bg-primary)] overflow-hidden relative">

                {/* FLOATING ZEN TOOLBAR */}
                <div className={`absolute top-6 left-1/2 -translate-x-1/2 z-50 transition-all duration-700 ${zenMode ? 'translate-y-0 scale-100 opacity-100' : '-translate-y-32 opacity-0'}`}>
                    <div className="bg-zinc-900/90 backdrop-blur-xl border border-white/10 p-2 rounded-2xl shadow-2xl flex items-center gap-4">
                        <button onClick={toggleZenMode} className="w-10 h-10 rounded-xl bg-white/10 hover:bg-white/20 text-white transition-all">
                            <i className="fa-solid fa-compress"></i>
                        </button>
                        <div className="h-6 w-px bg-white/10"></div>
                        <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest px-2">ZEN MODU AKTİF</span>
                    </div>
                </div>

                {/* STANDARD TOOLBAR */}
                {!zenMode && activityType && (processedData.length > 0 || isLoading) && (
                    <div className="shrink-0 bg-[var(--bg-paper)] border-b border-[var(--border-color)] p-4 z-40 shadow-sm">
                        <Toolbar 
                            settings={styleSettings} 
                            onSettingsChange={onStyleChange} 
                            onSave={() => onSave('Etkinlik', activityType, processedData)} 
                            onTogglePreview={toggleZenMode}
                            isPreviewMode={zenMode}
                            worksheetData={processedData}
                        />
                    </div>
                )}

                {/* THE DESK SURFACE */}
                <div 
                    ref={scrollContainerRef}
                    className={`flex-1 relative overflow-auto custom-scrollbar transition-all duration-700 ${zenMode ? 'bg-[#050505]' : 'bg-[var(--bg-secondary)]'}`}
                >
                    <div className="w-full flex flex-col items-center justify-start min-h-full py-12">
                        {isLoading ? (
                            <div className="py-20 w-full flex flex-col items-center">
                                <SkeletonLoader />
                                <p className="mt-8 font-black text-indigo-500 animate-pulse tracking-[0.3em] uppercase">AI Motoru İnşa Ediyor...</p>
                            </div>
                        ) : processedData.length > 0 ? (
                            <div 
                                className="transition-transform duration-200 ease-out will-change-transform shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)]"
                                style={{ transform: `scale(${scale})`, transformOrigin: 'top center' }}
                            >
                                <Worksheet activityType={activityType} data={processedData} settings={styleSettings} />
                            </div>
                        ) : (
                            <div className="py-40 text-center opacity-20 select-none">
                                <i className="fa-solid fa-wand-sparkles text-8xl mb-6"></i>
                                <h2 className="text-4xl font-black uppercase tracking-tighter">Bursa Disleksi AI</h2>
                                <p className="font-bold mt-2">Bir etkinlik seçerek sihirli süreci başlatın.</p>
                            </div>
                        )}
                    </div>

                    {/* ZOOM CONTROL */}
                    <div className="fixed bottom-8 right-8 z-50 flex flex-col gap-2">
                         <button onClick={() => setScale(s => Math.min(2.5, s + 0.1))} className="w-10 h-10 bg-white dark:bg-zinc-800 text-zinc-800 dark:text-white rounded-full shadow-xl border border-zinc-200 dark:border-zinc-700 flex items-center justify-center hover:scale-110 transition-all"><i className="fa-solid fa-plus"></i></button>
                         <button onClick={() => setScale(s => Math.max(0.3, s - 0.1))} className="w-10 h-10 bg-white dark:bg-zinc-800 text-zinc-800 dark:text-white rounded-full shadow-xl border border-zinc-200 dark:border-zinc-700 flex items-center justify-center hover:scale-110 transition-all"><i className="fa-solid fa-minus"></i></button>
                         <div className="bg-zinc-900 text-white px-3 py-1 rounded-lg text-[9px] font-black text-center shadow-lg">% {Math.round(scale * 100)}</div>
                    </div>
                </div>
            </main>
        </EditableContext.Provider>
    );
};

export default memo(ContentArea);

