interface ToolbarProps {
  settings: StyleSettings;
  onSettingsChange: (newSettings: StyleSettings) => void;
  onSave: () => void;
  onTogglePreview: () => void;
  isPreviewMode: boolean;
  worksheetData?: WorksheetData;
}

const IconButton = ({ icon, onClick, active, title, colorClass }: any) => (
    <button 
        onClick={onClick}
        title={title}
        className={`w-9 h-9 flex items-center justify-center rounded-xl transition-all duration-200 ${
            active 
            ? 'bg-zinc-900 text-white dark:bg-white dark:text-black shadow-lg scale-110' 
            : `text-zinc-500 hover:bg-zinc-100 dark:hover:bg-zinc-800 ${colorClass || 'hover:text-zinc-900'}`
        }`}
    >
        <i className={`fa-solid ${icon}`}></i>
    </button>
);

export const Toolbar: React.FC<ToolbarProps> = ({ settings, onSettingsChange, onSave, onTogglePreview }) => {
    const updateSetting = (key: keyof StyleSettings, value: any) => {
        onSettingsChange({ ...settings, [key]: value });
    };

    return (
        <div className="flex items-center justify-between gap-4 h-10 select-none">
            <div className="flex items-center gap-2">
                <div className="flex bg-zinc-100 dark:bg-zinc-800 p-1 rounded-xl border border-zinc-200 dark:border-zinc-700">
                    <IconButton 
                        icon="fa-eye" title="Okuma Odak Cetveli" 
                        active={settings.focusMode} 
                        onClick={() => updateSetting('focusMode', !settings.focusMode)} 
                    />
                    <IconButton 
                        icon="fa-font" title="Disleksi Dostu Yazı Tipi" 
                        active={settings.fontFamily === 'OpenDyslexic'} 
                        onClick={() => updateSetting('fontFamily', settings.fontFamily === 'OpenDyslexic' ? 'Lexend' : 'OpenDyslexic')} 
                    />
                </div>

                <div className="h-6 w-px bg-zinc-300 dark:bg-zinc-700"></div>

                <div className="flex items-center gap-2">
                    <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest hidden lg:block">Punto</span>
                    <div className="flex items-center bg-zinc-100 dark:bg-zinc-800 rounded-lg px-2 py-1">
                        <button onClick={() => updateSetting('fontSize', Math.max(12, settings.fontSize - 2))} className="text-zinc-400 hover:text-zinc-900"><i className="fa-solid fa-minus text-[10px]"></i></button>
                        <span className="w-8 text-center text-xs font-black">{settings.fontSize}</span>
                        <button onClick={() => updateSetting('fontSize', Math.min(48, settings.fontSize + 2))} className="text-zinc-400 hover:text-zinc-900"><i className="fa-solid fa-plus text-[10px]"></i></button>
                    </div>
                </div>
            </div>

            <div className="flex items-center gap-3">
                <button 
                    onClick={onTogglePreview} 
                    className="px-4 py-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-xl text-xs font-black hover:bg-indigo-100 transition-all flex items-center gap-2"
                >
                    <i className="fa-solid fa-expand"></i> ODAKLAN
                </button>
                <div className="flex bg-zinc-900 dark:bg-white p-1 rounded-xl shadow-xl">
                    <IconButton icon="fa-print" title="Yazdır (PDF)" colorClass="text-white dark:text-black" onClick={async () => await printService.generatePdf('.worksheet-page', 'Etkinlik', { action: 'print' })} />
                    <IconButton icon="fa-camera" title="Snapshot Al" colorClass="text-white dark:text-black" onClick={() => snapshotService.takeSnapshot('.worksheet-page', 'snapshot')} />
                    <IconButton icon="fa-save" title="Kaydet" colorClass="text-white dark:text-black" onClick={onSave} />
                </div>
            </div>
        </div>
    );
};

